@app.route('/api/orders', methods=['POST'])
@track_request
def create_order():
    data = request.get_json() or {}
    
    product_type = data.get('product_type', 'standard')
    order_value = data.get('value', random.uniform(10, 1000))
    
    start_time = time.time()
    time.sleep(random.uniform(0.01, 0.1))
    BUSINESS_DB_QUERY_DURATION.labels(query_type='insert', table='orders').observe(time.time() - start_time)
    
    status = 'completed' if random.random() > 0.1 else 'pending'
    
    BUSINESS_ORDERS_TOTAL.labels(product_type=product_type, status=status).inc()
    BUSINESS_ORDER_VALUE.labels(product_type=product_type).observe(order_value)
    
    if status == 'pending' and random.random() > 0.9:
        BUSINESS_ERROR_COUNT.labels(error_type='payment_failed', severity='warning').inc()
    
    return jsonify({
        'order_id': random.randint(1000, 9999),
        'product_type': product_type,
        'value': order_value,
        'status': status
    }), 201


@app.route('/api/inventory/<product_id>')
@track_request
def get_inventory(product_id):
    warehouses = ['warehouse_a', 'warehouse_b', 'warehouse_c']
    
    start_time = time.time()
    time.sleep(random.uniform(0.005, 0.05))
    BUSINESS_DB_QUERY_DURATION.labels(query_type='select', table='inventory').observe(time.time() - start_time)
    
    inventory_data = {}
    for warehouse in warehouses:
        level = random.randint(0, 500)
        BUSINESS_INVENTORY_LEVEL.labels(product_id=product_id, warehouse=warehouse).set(level)
        inventory_data[warehouse] = level
    
    return jsonify({
        'product_id': product_id,
        'inventory': inventory_data,
        'timestamp': time.time()
    })


